  // Helper to get available radii based on vehicle type
  const getRadiiOptions = (type: string) => {
      switch(type) {
          case 'truck': return TRUCK_RADII;
          case 'agro': return AGRO_RADII;
          case 'cargo': return CARGO_RADII;
          case 'car': 
