                        placeholder="Пошук шин..." 
                        value={tyreSearch} 
                        onChange={e => {
                            const val = e.target.value;
                            setTyreSearch(val);
                            if (val === '') setTimeout(() => fetchTyres(0, true), 0);
                        }} 
                        onKeyDown={e => e.key==='Enter' && fetchTyres(0,true)} 
