                    <Settings size={16} className="text-[#FFC300]" /> <span>Масове управління</span>
                    <span className="text-xs normal-case text-white bg-zinc-600 px-2 py-0.5 rounded ml-1">обрано: {selectedTyreIds.size}</span>
