                    {/* NEW BULK CATEGORY SELECTOR */}
                    <div className="mr-2 border-r border-zinc-700 pr-2 hidden md:block">
                        <select 
                            value={bulkCategory}
                            onChange={(e) => handleBulkCategoryUpdate(e.target.value)}
