                    <div className="text-center font-bold">Сезон</div>
                    <div>Пост.</div>
                    <div>Назва</div>
                    <div className="text-center">R</div>
                    <div className="text-right">Ціна</div>
                    <div className="text-center">Дії</div>
                </div>

