          }
      }, 500);
      return () => clearTimeout(timer);
  }, [npSearchCity, selectedCityRef, novaPoshtaKey]);

  const fetchNpCities = async (term: string) => {
      if(!novaPoshtaKey) return;
      setIsNpLoadingCities(true);
      try {
          const res = await fetch('https://api.novaposhta.ua/v2.0/json/', {
              method: 'POST',
              body: JSON.stringify({
                  apiKey: novaPoshtaKey,
                  modelName: "Address",
                  calledMethod: "searchSettlements",
                  methodProperties: {
                      CityName: term,
                      Limit: "20",
                      Page: "1"
                  }
              })
          });
          const data = await res.json();
          if (data.success && data.data && data.data[0]) {
              setNpCities(data.data[0].Addresses || []);
              setShowCityDropdown(true);
          } else {
              setNpCities([]);
          }
      } catch (e) {
          console.error("NP API Error", e);
      } finally {
          setIsNpLoadingCities(false);
      }
  };

  const fetchNpWarehouses = async (cityRef: string) => {
