</div>)}</div><select value={selectedWarehouseName} onChange={e => setSelectedWarehouseName(e.target.value)} disabled={!selectedCityRef || isNpLoadingWarehouses} className="w-full bg-black border border-zinc-700 rounded p-2 text-white disabled:opacity-50"><option value="">{isNpLoadingWarehouses ? 'Завантаження...' : 'Оберіть відділення'}</option>{npWarehouses.map((w: any) => (<option key={w.Ref} value={w.Description}>{w.Description}</option>))}</select><div className="flex gap-2 pt-1"><label className="flex items-center gap-1 text-xs text-zinc-400 cursor-pointer"><input type="radio" checked={paymentMethod === 'prepayment'} onChange={() => setPaymentMethod('prepayment')} className="accent-red-500" /> Предоплата</label><label className="flex items-center gap-1 text-xs text-zinc-400 cursor-pointer"><input type="radio" checked={paymentMethod === 'full'} onChange={() => setPaymentMethod('full')} className="accent-red-500" /> Повна оплата</label></div></div>)}</div>
