  const [shopPhone, setShopPhone] = useState(PHONE_NUMBER_1);
  const [shopPhoneLink, setShopPhoneLink] = useState(PHONE_LINK_1);

  const [orderName, setOrderName] = useState('');
  const [orderPhone, setOrderPhone] = useState('');
  const [deliveryMethod, setDeliveryMethod] = useState<'pickup' | 'newpost'>('pickup');
  const [paymentMethod, setPaymentMethod] = useState<'prepayment' | 'full'>('prepayment');

  const [npSearchCity, setNpSearchCity] = useState('');
  const [npCities, setNpCities] = useState<any[]>([]);
  const [npWarehouses, setNpWarehouses] = useState<any[]>([]);
  const [selectedCityRef, setSelectedCityRef] = useState('');
  const [selectedCityName, setSelectedCityName] = useState('');
  const [selectedWarehouseName, setSelectedWarehouseName] = useState('');
  const [isNpLoadingCities, setIsNpLoadingCities] = useState(false);
  const [isNpLoadingWarehouses, setIsNpLoadingWarehouses] = useState(false);
  const [showCityDropdown, setShowCityDropdown] = useState(false);

  const [orderSending, setOrderSending] = useState(false);
  const [orderSuccess, setOrderSuccess] = useState(false);
  const [orderError, setOrderError] = useState('');

  const touchStartRef = useRef<number | null>(null);
  const touchEndRef = useRef<number | null>(null);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const prodId = params.get('product_id');
    if (prodId) {
        const fetchDeepLinkProduct = async () => {
            const { data } = await supabase.from('tyres').select('*').eq('id', prodId).single();
            if (data) {
                const parsed = parseTyreSpecs(data);
                if (parsed.in_stock !== false) setSelectedProductForModal(parsed);
            }
        };
        fetchDeepLinkProduct();
    }
  }, []);

  const updateUrlForProduct = (product: TyreProduct | null) => {
    try {
      const searchParams = new URLSearchParams(window.location.search);
      if (product) {
          searchParams.set('product_id', String(product.id));
          const newUrl = window.location.pathname + '?' + searchParams.toString();
          window.history.pushState({ productId: product.id }, '', newUrl);
          document.title = `${product.title} - Купити в Синельниковому | Форсаж`;
      } else {
          searchParams.delete('product_id');
          const searchStr = searchParams.toString();
          const newUrl = window.location.pathname + (searchStr ? '?' + searchStr : '');
          window.history.pushState({}, '', newUrl);
          document.title = 'Магазин Шин та Дисків | Форсаж Синельникове';
      }
    } catch (e) { console.warn("URL history update skipped:", e); }
  };

  const handleProductClick = (tyre: TyreProduct) => {
      if (tyre.in_stock !== false) {
          setSelectedProductForModal(tyre);
          updateUrlForProduct(tyre);
      }
  };

  const handleCloseModal = () => {
      setSelectedProductForModal(null);
      updateUrlForProduct(null);
  };

  const fetchNpCities = async (term: string) => {
      if(!novaPoshtaKey) return;
      setIsNpLoadingCities(true);
      try {
          const res = await fetch('https://api.novaposhta.ua/v2.0/json/', {
              method: 'POST',
              body: JSON.stringify({ apiKey: novaPoshtaKey, modelName: "Address", calledMethod: "searchSettlements", methodProperties: { CityName: term, Limit: "20", Page: "1" } })
          });
          const data = await res.json();
          if (data.success && data.data && data.data[0]) {
              setNpCities(data.data[0].Addresses || []);
              setShowCityDropdown(true);
          } else setNpCities([]);
      } catch (e) { console.error("NP API Error", e); } finally { setIsNpLoadingCities(false); }
  };

  const fetchNpWarehouses = async (cityRef: string) => {
      if(!novaPoshtaKey) return;
      setIsNpLoadingWarehouses(true);
      try {
          const res = await fetch('https://api.novaposhta.ua/v2.0/json/', {
              method: 'POST',
              body: JSON.stringify({ apiKey: novaPoshtaKey, modelName: "Address", calledMethod: "getWarehouses", methodProperties: { CityRef: cityRef, Language: "UA" } })
          });
          const data = await res.json();
          if (data.success) setNpWarehouses(data.data);
      } catch (e) { console.error("NP Warehouse Error", e); } finally { setIsNpLoadingWarehouses(false); }
  };

  const handleCitySelect = (city: any) => {
      const cityName = city.Present; 
      const cityRef = city.DeliveryCity; 
      setNpSearchCity(cityName);
      setSelectedCityName(cityName);
      setSelectedCityRef(cityRef);
      setNpCities([]);
      setShowCityDropdown(false);
      setSelectedWarehouseName('');
      setNpWarehouses([]);
      fetchNpWarehouses(cityRef);
  };

  const handleCityInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      setNpSearchCity(e.target.value);
      setSelectedCityRef('');
      setSelectedCityName('');
      setShowCityDropdown(true);
  };

  useEffect(() => {
    const fetchSettingsAndFilters = async () => {
      const { data: setts } = await supabase.from('settings').select('key, value').in('key', ['enable_stock_quantity', 'promo_data', 'contact_phone1', 'nova_poshta_key']);
      if (setts) {
          setts.forEach(item => {
              if (item.key === 'enable_stock_quantity') setEnableStockQty(item.value === 'true');
              if (item.key === 'contact_phone1') { setShopPhone(item.value); setShopPhoneLink(`tel:${item.value.replace(/[^\d+]/g, '')}`); }
              if (item.key === 'nova_poshta_key') setNovaPoshtaKey(item.value);
              if (item.key === 'promo_data' && item.value) { try { const p = JSON.parse(item.value); setPromoBanner(Array.isArray(p) ? p.find((x:any) => x.active) : (p.active ? p : null)); } catch (e) { console.error(e); } }
          });
      }
      const { data: tData } = await supabase.from('tyres').select('manufacturer, radius, title').neq('in_stock', false);
      if (tData) {
          const brands = new Set<string>(), radii = new Set<string>(), widths = new Set<string>(), heights = new Set<string>();
          tData.forEach(item => {
              if (item.manufacturer) { let b = item.manufacturer.trim(); if (['Ш.Ханкук тайр', 'Ш.Ханкук Тайр', 'Lfufen'].includes(b)) b = 'Laufenn'; brands.add(b); }
              if (item.radius) radii.add(item.radius.trim());
              const m = item.title.match(/(\d{3})[\/\s](\d{2})/);
              if (m) { widths.add(m[1]); heights.add(m[2]); }
          });
          setFilterOptions({ brands: Array.from(brands).sort(), radii: Array.from(radii).sort((a, b) => parseFloat(a.replace(/[^\d.]/g, '')) - parseFloat(b.replace(/[^\d.]/g, ''))), widths: Array.from(widths).sort(), heights: Array.from(heights).sort() });
      }
    };
    fetchSettingsAndFilters();
  }, []);

  useEffect(() => { if (initialCategory) setActiveCategory(initialCategory); }, [initialCategory]);

  useEffect(() => {
    setPage(0);
    setTyres([]); 
    fetchTyres(0, true);
  }, [activeCategory, activeSort, enableStockQty, filterBrand, filterRadius, filterWidth, filterHeight, showOnlyInStock]);

  const parseTyreSpecs = (tyre: TyreProduct): TyreProduct => {
    const m = tyre.title.match(/(\d{3})[\/\s](\d{2})[\s\w]*R(\d{2}(?:\.5|\.3)?[C|c]?)/) || tyre.description?.match(/(\d{3})[\/\s](\d{2})[\s\w]*R(\d{2}(?:\.5|\.3)?[C|c]?)/);
    let width = '', height = '', parsedRadius = tyre.radius || '', vehicle_type = tyre.vehicle_type || 'car';
    if (m) { width = m[1]; height = m[2]; const r = m[3].toUpperCase(); if (!parsedRadius) parsedRadius = `R${r}`; if (vehicle_type === 'car' && r.endsWith('C')) vehicle_type = 'cargo'; }
    if (vehicle_type === 'car') { const u = tyre.title.toUpperCase(); if (['R12C','R13C','R14C','R15C','R16C','LT'].some(x => u.includes(x))) vehicle_type = 'cargo'; }
    const lt = (tyre.title + ' ' + tyre.description).toLowerCase();
    let season = tyre.season || 'all'; 
    if (!tyre.season) { if (['зима','winter','snow','ice'].some(x => lt.includes(x))) season = 'winter'; else if (['літо','summer'].some(x => lt.includes(x))) season = 'summer'; else if (['всесезон','all season'].some(x => lt.includes(x))) season = 'all-season'; }
    if (vehicle_type === 'agro') season = 'all-season';
    let in_stock = enableStockQty ? (tyre.in_stock !== false && (tyre.stock_quantity ?? 0) > 0) : true;
    let manufacturer = tyre.manufacturer || '';
    if (['Ш.Ханкук тайр', 'Ш.Ханкук Тайр', 'Lfufen'].includes(manufacturer)) manufacturer = 'Laufenn';
    return { ...tyre, width, height, radius: parsedRadius, season, vehicle_type, in_stock, manufacturer };
  };

  const fetchTyres = async (pageIndex: number, isRefresh = false) => {
    try {
      if (isRefresh) setLoading(true); else setLoadingMore(true);
      const from = pageIndex * PAGE_SIZE, to = from + PAGE_SIZE - 1;
      let query = supabase.from('tyres').select('*', { count: 'exact' });
      if (searchQuery.trim()) query = query.or(`title.ilike.%${searchQuery.trim()}%,catalog_number.ilike.%${searchQuery.trim()}%,manufacturer.ilike.%${searchQuery.trim()}%,product_number.ilike.%${searchQuery.trim()}%`);
      if (filterBrand) { if (filterBrand === 'Laufenn') query = query.or('manufacturer.eq.Laufenn,manufacturer.eq.Ш.Ханкук тайр,manufacturer.eq.Ш.Ханкук Тайр'); else query = query.eq('manufacturer', filterBrand); }
      if (filterRadius) query = query.eq('radius', filterRadius);
      if (filterWidth) query = query.ilike('title', `%${filterWidth}%`);
      if (filterHeight) query = query.ilike('title', `%/${filterHeight}%`);
      if (showOnlyInStock) query = enableStockQty ? query.or('stock_quantity.gt.0,stock_quantity.is.null').neq('in_stock', false) : query.neq('in_stock', false);

      if (activeCategory === 'hot_light') query = query.eq('is_hot', true).or('vehicle_type.eq.car,vehicle_type.eq.suv,vehicle_type.eq.cargo,vehicle_type.is.null');
      else if (activeCategory === 'hot_heavy') query = query.eq('is_hot', true).or('vehicle_type.eq.truck,vehicle_type.eq.agro');
      else if (['winter','summer','all-season'].includes(activeCategory)) query = query.or(`title.ilike.%${activeCategory}%,description.ilike.%${activeCategory}%`);
      else if (activeCategory === 'cargo') query = query.or('vehicle_type.eq.cargo,radius.ilike.%C%').not('radius', 'in', '("R17.5","R19.5","R22.5")');
      else if (activeCategory === 'truck') query = query.or('radius.eq.R17.5,radius.eq.R19.5,radius.eq.R22.5,title.ilike.%TIR%,title.ilike.%R17.5%,title.ilike.%R19.5%,title.ilike.%R22.5%');
      else if (activeCategory === 'agro') query = query.or(`vehicle_type.eq.agro,and(vehicle_type.neq.car,vehicle_type.neq.suv,vehicle_type.neq.cargo,or(radius.in.("R10","R12","R14.5","R15.3","R15.5","R24","R26","R28","R30","R32","R34","R36","R38","R40","R42","R44","R46","R48","R50","R52"),title.ilike.%PR%,title.ilike.%OZKA%,title.ilike.%BKT%))`).not('title','ilike','%(C)%').not('title','ilike','% LT%');
      else if (activeCategory === 'out_of_stock') query = enableStockQty ? query.or('in_stock.eq.false,stock_quantity.eq.0') : query.eq('in_stock', false);

      if (minPrice) query = query.gte('price', parseInt(minPrice));
      if (maxPrice) query = query.lte('price', parseInt(maxPrice));
      if (enableStockQty) query = query.order('in_stock', { ascending: false });

      const sorts = { with_photo: 'image_url', no_photo: 'image_url', price_asc: 'price', price_desc: 'price', oldest: 'created_at' };
      query = query.order((sorts as any)[activeSort] || 'created_at', { ascending: ['price_asc','oldest','no_photo'].includes(activeSort) });

      const { data, error } = await query.range(from, to);
      if (error) throw error;
      if (data) {
        let processed = data.map(parseTyreSpecs);
        if (activeSort === 'with_photo') processed = processed.sort((a,b) => (b.image_url?.length ?? 0) - (a.image_url?.length ?? 0));
        setTyres(isRefresh ? processed : prev => [...prev, ...processed]); 
        setPage(pageIndex);
        setHasMore(data.length === PAGE_SIZE);
      }
    } catch (error) { console.error(error); } finally { setLoading(false); setLoadingMore(false); }
  };

  const addToCart = (tyre: TyreProduct) => { 
      if (!tyre.in_stock) return; 
      setCart(prev => { 
          const ex = prev.find(item => item.id === tyre.id);
          if (enableStockQty && (tyre.stock_quantity ?? 0) > 0 && (ex?.quantity ?? 0) + 1 > tyre.stock_quantity!) { alert(`Лише ${tyre.stock_quantity} шт.`); return prev; }
          return ex ? prev.map(i => i.id === tyre.id ? { ...i, quantity: i.quantity + 1 } : i) : [...prev, { ...tyre, quantity: 1 }]; 
      }); 
      setIsCartOpen(true); 
  };

  const submitOrder = async () => {
    if (!orderName || orderPhone.length < 9) { setOrderError("Введіть дані"); return; }
    if (deliveryMethod === 'newpost' && (!selectedCityName || !selectedWarehouseName)) { setOrderError("Оберіть доставку"); return; }
    setOrderSending(true); setOrderError('');
    try {
      const { error } = await supabase.from('tyre_orders').insert([{ customer_name: orderName, customer_phone: orderPhone, status: 'new', delivery_method: deliveryMethod, delivery_city: selectedCityName, delivery_warehouse: selectedWarehouseName, payment_method: paymentMethod, items: cart.map(i => ({ id: i.id, title: i.title, quantity: i.quantity, price: i.price, base_price: i.base_price })) }]);
      if (error) throw error;
      await fetch(FORMSPREE_ENDPOINT, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ subject: `Замовлення шин`, customer_name: orderName, customer_phone: orderPhone, items: cart.map(i => `${i.title} (${i.quantity})`).join('\n') }) });
      setOrderSuccess(true); setCart([]);
    } catch (err) { setOrderError("Помилка замовлення"); } finally { setOrderSending(false); }
  };

  const renderSchema = (product: TyreProduct) => {
    const s = { "@context": "https://schema.org/", "@type": "Product", "name": product.title, "image": product.image_url, "offers": { "@type": "Offer", "price": safeParsePrice(product.price), "priceCurrency": "UAH", "availability": product.in_stock ? "InStock" : "OutOfStock" } };
    return <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(s) }} />;
  };

  return (
    <div className="min-h-screen bg-[#09090b] py-8 md:py-12 animate-in fade-in pb-32">
      <div className="max-w-7xl mx-auto px-2 md:px-4">
        {/* HEADER & FILTERS */}
        <div className="flex flex-col lg:flex-row justify-between items-start md:items-center gap-4 mb-8 px-2">
           <div>
              <h2 className="text-3xl md:text-4xl font-black text-white mb-2 border-b-2 border-[#FFC300] inline-block pb-2">Магазин Шин та Дисків</h2>
              <p className="text-zinc-400">Широкий вибір у Синельниковому.</p>
           </div>
           <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-xl flex items-center gap-4">
              <div className="p-2 bg-[#FFC300] rounded-full text-black"><Phone size={20}/></div>
              <div><p className="text-xs text-zinc-500 font-bold uppercase">Консультація</p><a href={shopPhoneLink} className="text-white font-bold text-lg">{shopPhone}</a></div>
        </div>
      </div>

        {/* CATEGORY NAV */}
        <div className="mb-8 px-2"><div className="grid grid-cols-3 sm:grid-cols-4 lg:grid-cols-10 gap-2 md:gap-3">{CATEGORIES.map(cat => (<button key={cat.id} onClick={() => setActiveCategory(cat.id)} className={`flex flex-col items-center justify-center gap-1.5 p-2 rounded-xl border transition-all ${activeCategory === cat.id ? 'bg-[#FFC300] text-black scale-105' : 'bg-zinc-900 border-zinc-800 text-zinc-400 hover:text-white'}`}><cat.icon size={18} /><span className="font-bold text-[10px] uppercase text-center leading-tight">{cat.label}</span></button>))}</div></div>

        {/* SEARCH & SORT */}
        <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-2xl mb-8 mx-2 space-y-4">
          <div className="flex gap-2"><div className="relative flex-grow"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={18}/><input type="text" placeholder="Пошук..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} onKeyDown={e => e.key==='Enter' && fetchTyres(0,true)} className="w-full bg-black border border-zinc-700 rounded-xl pl-10 pr-4 py-3 text-white outline-none focus:border-[#FFC300]" /></div><button onClick={() => setShowOnlyInStock(!showOnlyInStock)} className={`hidden md:flex items-center gap-2 px-4 rounded-xl border transition-colors ${showOnlyInStock ? 'bg-green-600 text-white' : 'bg-black text-zinc-500'}`}>{showOnlyInStock ? <Eye size={20}/> : <EyeOff size={20}/>}</button><button onClick={() => fetchTyres(0,true)} className="bg-[#FFC300] text-black font-black px-6 py-3 rounded-xl">ЗНАЙТИ</button></div>
          <div className="flex flex-col sm:flex-row gap-2"><div className="grid grid-cols-2 md:grid-cols-4 gap-2 flex-grow">{['Width','Height','Radius','Brand'].map((f, i) => (<select key={f} value={(this as any)[`filter${f}`]} onChange={e => (this as any)[`setFilter${f}`](e.target.value)} className="bg-black text-white p-3 rounded-xl border border-zinc-800"><option value="">{f}</option>{(filterOptions as any)[`${f.toLowerCase()}s`]?.map((v:any) => <option key={v} value={v}>{v}</option>)}</select>))}</div></div>
        </div>

        {/* PRODUCTS GRID */}
        {loading ? (
           <div className="flex justify-center py-20 text-[#FFC300]"><Loader2 className="animate-spin" size={48} /></div>
        ) : tyres.length === 0 ? (
           <div className="text-center py-20 bg-zinc-900 rounded-xl border border-zinc-800 mx-2 text-zinc-500">Шин не знайдено</div>
        ) : (
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 md:gap-6 px-2">
             {tyres.map((tyre) => (
                <div key={tyre.id} onClick={() => handleProductClick(tyre)} className={`h-full bg-zinc-900 border rounded-xl overflow-hidden hover:border-[#FFC300] transition-colors group flex flex-col relative ${!tyre.in_stock ? 'opacity-70' : 'border-zinc-800'}`}>
                   <div className="aspect-square bg-black relative cursor-pointer">{tyre.image_url && tyre.in_stock ? <img src={tyre.image_url} className="w-full h-full object-cover group-hover:scale-105 duration-500" /> : <div className="w-full h-full flex flex-col items-center justify-center text-zinc-700 bg-zinc-950">Немає фото</div>}</div>
                   <div className="p-3 md:p-4 flex flex-col flex-grow">
                      <h3 className="text-sm md:text-base font-bold text-white mb-2 leading-tight line-clamp-2 min-h-[2.5em]">{tyre.title}</h3>
                      <div className="text-[10px] text-zinc-500 mb-2 flex flex-col gap-0.5">
                        {tyre.catalog_number && <span>Арт: <span className="text-zinc-400 font-mono">{tyre.catalog_number}</span></span>}
                        {(tyre.width || tyre.height || tyre.radius) && <span className="text-[#FFC300] font-black uppercase mt-0.5 text-[11px]">{tyre.width}/{tyre.height} {tyre.radius}</span>}
                      </div>
                      <div className="mt-auto pt-3 border-t border-zinc-800 flex flex-col gap-2"><span className="text-xl font-black text-[#FFC300]">{formatPrice(tyre.price)} грн</span><button onClick={e => { e.stopPropagation(); addToCart(tyre); }} disabled={!tyre.in_stock} className={`w-full py-3 rounded-lg font-bold text-xs uppercase ${!tyre.in_stock ? 'bg-zinc-800 text-zinc-500' : 'bg-white text-black hover:bg-[#FFC300]'}`}>Купити</button></div>
                   </div>
                </div>
             ))}
          </div>
        )}
        {hasMore && <div className="mt-12 text-center"><button onClick={() => fetchTyres(page+1)} disabled={loadingMore} className="bg-zinc-800 text-white font-bold py-3 px-8 rounded-xl border border-zinc-700">{loadingMore ? <Loader2 className="animate-spin" /> : <ArrowDown size={20} />} Завантажити ще</button></div>}
      </div>

      {/* FLOATING CART BUTTON */}
      {cart.length > 0 && <button onClick={() => setIsCartOpen(true)} className="fixed bottom-6 right-6 z-40 bg-[#FFC300] text-black p-4 rounded-full shadow-lg animate-bounce"><ShoppingCart size={28} /></button>}

      {/* EXTERNAL COMPONENTS */}
      <CartDrawer 
        isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} cart={cart} cartTotal={useMemo(() => cart.reduce((a,b) => a + (safeParsePrice(b.price)*b.quantity), 0), [cart])}
        enableStockQty={enableStockQty} orderName={orderName} setOrderName={setOrderName} orderPhone={orderPhone} setOrderPhone={setOrderPhone}
        deliveryMethod={deliveryMethod} setDeliveryMethod={setDeliveryMethod} paymentMethod={paymentMethod} setPaymentMethod={setPaymentMethod}
        npSearchCity={npSearchCity} handleCityInputChange={handleCityInputChange} isNpLoadingCities={isNpLoadingCities} showCityDropdown={showCityDropdown} npCities={npCities} handleCitySelect={handleCitySelect}
        selectedWarehouseName={selectedWarehouseName} setSelectedWarehouseName={setSelectedWarehouseName} isNpLoadingWarehouses={isNpLoadingWarehouses} npWarehouses={npWarehouses} selectedCityRef={selectedCityRef}
        updateQuantity={(id, d) => setCart(prev => prev.map(i => i.id === id ? { ...i, quantity: Math.max(1, i.quantity + d) } : i))} removeFromCart={id => setCart(prev => prev.filter(i => i.id !== id))}
        submitOrder={submitOrder} orderSending={orderSending} orderSuccess={orderSuccess} orderError={orderError} setOrderSuccess={setOrderSuccess} formatPrice={formatPrice}
      />

      <ProductDetailModal 
        product={selectedProductForModal} onClose={handleCloseModal} openLightbox={p => { setCurrentLightboxImages([p.image_url, ...(p.gallery || [])].filter(x=>x)); setLightboxOpen(true); }}
        enableStockQty={enableStockQty} getSeasonLabel={getSeasonLabel} formatPrice={formatPrice} addToCart={addToCart} renderSchema={renderSchema}
      />

      {/* LIGHTBOX */}
      {lightboxOpen && <div className="fixed inset-0 z-[200] bg-black flex items-center justify-center p-4"><button onClick={() => setLightboxOpen(false)} className="absolute top-4 right-4 text-white"><X size={32}/></button><img src={currentLightboxImages[currentImageIndex]} className="max-w-full max-h-full object-contain" /></div>}
    </div>
  );
};

export default TyreShop;

import React from 'react';
import { X, Upload, Save, Loader2, Snowflake, Sun, CloudSun, Flame, CircleDot } from 'lucide-react';
import { KNOWN_BRANDS, AXIS_OPTIONS } from '../TyresTab';

interface TyreEditModalProps {
  editingId: number | null;
  form: any;
  setForm: (f: any) => void;
  onClose: () => void;
  onSave: () => void;
  uploading: boolean;
  radii: string[];
  existingGallery: string[];
  setExistingGallery: (urls: string[]) => void;
  setFiles: (files: File[]) => void;
  filesCount: number;
  applyDiscount: (pct: number) => void;
}

const TyreEditModal: React.FC<TyreEditModalProps> = (props) => {
  const { form, setForm } = props;

  return (
    <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4 outline-none" 
         onPaste={(e: React.ClipboardEvent) => {
            if (e.clipboardData.files.length > 0) {
                e.preventDefault();
                props.setFiles(Array.from(e.clipboardData.files).filter(f => f.type.startsWith('image/')));
            }
         }}>
      <div className="bg-zinc-900 border border-zinc-700 p-6 rounded-2xl w-full max-w-4xl h-[90vh] flex flex-col shadow-2xl relative" onClick={e => e.stopPropagation()}>
