          <button onClick={props.onSave} disabled={props.uploading} className="px-8 py-3 bg-[#FFC300] text-black font-black rounded-xl flex items-center gap-2">
            {props.uploading ? <Loader2 className="animate-spin"/> : <Save size={20}/>} Зберегти
          </button>
