const PAGE_SIZE = 50;
export const KNOWN_BRANDS = ['NOKIAN', 'MICHELIN', 'CONTINENTAL', 'BRIDGESTONE', 'GOODYEAR', 'PIRELLI', 'HANKOOK', 'YOKOHAMA', 'TOYO', 'KUMHO', 'NEXEN', 'DUNLOP', 'PREMIORRI', 'ROSAVA', 'BELSHINA', 'TRIANGLE', 'SAILUN', 'LINGLONG', 'LAUFENN', 'COOPER', 'MATADOR', 'BARUM', 'SAVA', 'FULDA', 'KELLY', 'DEBICA', 'GENERAL', 'GISLAVED', 'VIKING', 'RIKEN', 'KORMORAN', 'KLEBER', 'BFGOODRICH', 'TIGAR', 'UNIROYAL', 'FIRESTONE', 'DAYTON', 'LASSA', 'STARMAXX', 'PETLAS', 'HIFLY', 'DOUBLESTAR', 'ETERNITY', 'OZKA', 'BKT', 'SEHA'];
export const AXIS_OPTIONS = ['Ведуча', 'Причіпна', 'Рульова', 'Рульова, автобусна', 'Рульова/Причіпна', 'Універсальна'];

const detectSeason = (title: string, description: string): string | null => {
    const text = (title + ' ' + (description || '')).toLowerCase();
    if (['зима','зимн','winter','snow','ice','stud','spike','alpin','nord','arct','blizzak','w442','w452','i fit','kw31','rw','ws','dm'].some(x => text.includes(x))) return 'winter';
    if (['літо','літн','summer','sport','energy','premium','contact','control','turismo','potenza','lk01','lk41','lk41','prime','blue'].some(x => text.includes(x))) return 'summer';
    if (['всесезон','all season','allseason','4s','quatrac','cross','weather','as'].some(x => text.includes(x))) return 'all-season';
    return null;
};

const TyresTab: React.FC = () => {
  const [tyres, setTyres] = useState<TyreProduct[]>([]);
  const [loadingTyres, setLoadingTyres] = useState(false);
  const [hasMoreTyres, setHasMoreTyres] = useState(true);
  const [tyrePage, setTyrePage] = useState(0);
  const [totalCount, setTotalCount] = useState(0);
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');
  const [tyreSearch, setTyreSearch] = useState('');
  const [tyreCategoryTab, setTyreCategoryTab] = useState<'all' | 'car' | 'cargo' | 'truck' | 'agro' | 'suv' | 'hot' | 'out_of_stock' | 'no_photo'>('all');
  const [tyreSort, setTyreSort] = useState<'newest' | 'oldest' | 'price_asc' | 'price_desc' | 'with_photo' | 'no_photo'>('newest');
  const [filterSupplierId, setFilterSupplierId] = useState<string>('all');
  const [showOnlyInStock, setShowOnlyInStock] = useState(false);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [showCategoryMenu, setShowCategoryMenu] = useState(false);
  const [categoryCounts, setCategoryCounts] = useState({ all: 0, car: 0, cargo: 0, truck: 0, agro: 0, suv: 0, hot: 0, out: 0, no_photo: 0 });
  const [enableStockQty, setEnableStockQty] = useState(false);
  const [selectedTyreIds, setSelectedTyreIds] = useState<Set<number>>(new Set());
  const [bulkMarkup, setBulkMarkup] = useState('');
  const [bulkCategory, setBulkCategory] = useState('');
  const [isApplyingBulk, setIsApplyingBulk] = useState(false);
  const [showAddTyreModal, setShowAddTyreModal] = useState(false);
  const [editingTyreId, setEditingTyreId] = useState<number | null>(null);
  const [tyreForm, setTyreForm] = useState({ manufacturer: '', name: '', width: '', height: '', radius: 'R15', season: 'winter', vehicle_type: 'car' as any, price: '', old_price: '', base_price: '', catalog_number: '', product_number: '', description: '', is_hot: false, supplier_id: '', stock_quantity: '', axis: '' });
  const [tyreUploadFiles, setTyreUploadFiles] = useState<File[]>([]);
  const [existingGallery, setExistingGallery] = useState<string[]>([]);
  const [uploading, setUploading] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [tyreToDelete, setTyreToDelete] = useState<number | null>(null);
  const [deleteWithPhotos, setDeleteWithPhotos] = useState(false);
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showCategoryDeleteConfirm, setShowCategoryDeleteConfirm] = useState(false);

  useEffect(() => {
    const init = async () => {
      const { data: setts } = await supabase.from('settings').select('*').eq('key', 'enable_stock_quantity').single();
      if (setts) setEnableStockQty(setts.value === 'true');
      const { data: supps } = await supabase.from('suppliers').select('*').order('name');
      if (supps) setSuppliers(supps);
    };
    init();
  }, []);

  useEffect(() => { setTyres([]); setTyrePage(0); setHasMoreTyres(true); fetchTyres(0, true); fetchCategoryCounts(); }, [tyreCategoryTab, tyreSort, filterSupplierId, enableStockQty, showOnlyInStock]);

  const fetchCategoryCounts = async () => {
    try {
        const [all, car, cargo, truck, agro, suv, hot, out, no_photo] = await Promise.all([
            supabase.from('tyres').select('*', { count: 'exact', head: true }).then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).or('vehicle_type.eq.car,vehicle_type.is.null').neq('vehicle_type', 'cargo').neq('vehicle_type', 'suv').neq('vehicle_type', 'truck').neq('vehicle_type', 'agro').not('radius', 'ilike', '%C%').then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).or('vehicle_type.eq.cargo,radius.ilike.%C%').not('radius', 'in', '("R17.5","R19.5","R22.5")').then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).or('vehicle_type.eq.truck,radius.eq.R17.5,radius.eq.R19.5,radius.eq.R22.5,radius.eq.R24.5,title.ilike.%TIR%,title.ilike.%R17.5%,title.ilike.%R19.5%,title.ilike.%R22.5%').then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).or('vehicle_type.eq.agro,and(vehicle_type.neq.car,vehicle_type.neq.suv,vehicle_type.neq.cargo,vehicle_type.neq.truck,radius.in.("R10","R12","R14.5","R15.3","R15.5","R20","R24","R26","R28","R30","R32","R34","R36","R38","R40","R42","R44","R46","R48","R50","R52"))').then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).eq('vehicle_type', 'suv').then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).eq('is_hot', true).then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).eq('in_stock', false).then(r => r.count),
            supabase.from('tyres').select('*', { count: 'exact', head: true }).is('image_url', null).then(r => r.count)
        ]);
        setCategoryCounts({ all: all||0, car: car||0, cargo: cargo||0, truck: truck||0, agro: agro||0, suv: suv||0, hot: hot||0, out: out||0, no_photo: no_photo||0 });
    } catch (e) { console.error(e); }
  };

  const fetchTyres = async (pageIdx: number, isRefresh = false) => {
    setLoadingTyres(true);
    try {
       const from = pageIdx * PAGE_SIZE, to = from + PAGE_SIZE - 1;
       let query = supabase.from('tyres').select('*', { count: 'exact' });
       if (tyreSearch.trim()) tyreSearch.trim().split(/\s+/).forEach(t => { if(t) query = query.or(`title.ilike.%${t}%,catalog_number.ilike.%${t}%,radius.ilike.%${t}%,product_number.ilike.%${t}%,manufacturer.ilike.%${t}%`); });
       if (tyreCategoryTab === 'car') query = query.or('vehicle_type.eq.car,vehicle_type.is.null').neq('vehicle_type', 'cargo').neq('vehicle_type', 'suv').neq('vehicle_type', 'truck').neq('vehicle_type', 'agro').not('radius', 'ilike', '%C%');
       else if (tyreCategoryTab === 'cargo') query = query.or('vehicle_type.eq.cargo,radius.ilike.%C%').not('radius', 'in', '("R17.5","R19.5","R22.5")');
       else if (tyreCategoryTab === 'truck') query = query.or('vehicle_type.eq.truck,radius.eq.R17.5,radius.eq.R19.5,radius.eq.R22.5,radius.eq.R24.5,title.ilike.%TIR%,title.ilike.%R17.5%,title.ilike.%R19.5%,title.ilike.%R22.5%');
       else if (tyreCategoryTab === 'agro') query = query.or(`vehicle_type.eq.agro,and(vehicle_type.neq.car,vehicle_type.neq.suv,vehicle_type.neq.cargo,vehicle_type.neq.truck,or(radius.in.("R10","R12","R14.5","R15.3","R15.5","R24","R26","R28","R30","R32","R34","R36","R38","R40","R42","R44","R46","R48","R50","R52"),title.ilike.%PR%))`).not('title','ilike','%(C)%').not('title','ilike','% LT%');
       else if (tyreCategoryTab === 'suv') query = query.eq('vehicle_type', 'suv');
       else if (tyreCategoryTab === 'hot') query = query.eq('is_hot', true);
       else if (tyreCategoryTab === 'out_of_stock') query = query.eq('in_stock', false);
       else if (tyreCategoryTab === 'no_photo') query = query.is('image_url', null);

       if (showOnlyInStock) query = enableStockQty ? query.or('stock_quantity.gt.0,stock_quantity.is.null').neq('in_stock', false) : query.neq('in_stock', false);
       if (filterSupplierId !== 'all') query = query.eq('supplier_id', parseInt(filterSupplierId));
       query = query.order('in_stock', { ascending: false });
       if (tyreSort === 'newest') query = query.order('created_at', { ascending: false });
       else if (tyreSort === 'oldest') query = query.order('created_at', { ascending: true });
       else if (tyreSort === 'price_asc') query = query.order('price', { ascending: true });
       else if (tyreSort === 'price_desc') query = query.order('price', { ascending: false });

       const { data, error, count } = await query.range(from, to);
       if (error) throw error;
       if (count !== null) setTotalCount(count);
       if (data) {
          const processed = data.map(t => ({ ...t, season: detectSeason(t.title, t.description) || t.season || 'summer' }));
          setTyres(isRefresh ? processed : prev => [...prev, ...processed]);
          setTyrePage(pageIdx);
          setHasMoreTyres(data.length === PAGE_SIZE);
       }
    } catch (e: any) { setErrorMessage(e.message); } finally { setLoadingTyres(false); }
  };

  const handleSaveTyre = async () => {
    setUploading(true);
    try {
      const newUrls: string[] = [];
      for (const file of tyreUploadFiles) {
         const name = `tyre_${Date.now()}_${file.name.replace(/\s+/g, '_')}`;
         const { error } = await supabase.storage.from('galery').upload(name, file);
         if (!error) { const { data } = supabase.storage.from('galery').getPublicUrl(name); newUrls.push(data.publicUrl); }
      }
      const finalGallery = Array.from(new Set([...existingGallery, ...newUrls]));
      const forcedSeason = (tyreForm.vehicle_type === 'truck' || tyreForm.vehicle_type === 'agro') ? 'all-season' : tyreForm.season;
      const title = `${tyreForm.manufacturer} ${tyreForm.name} ${tyreForm.width}/${tyreForm.height} ${tyreForm.radius} ${forcedSeason}`.replace(/\s+/g, ' ').trim();
      const payload: any = { title, manufacturer: tyreForm.manufacturer, price: tyreForm.price, old_price: tyreForm.old_price, base_price: tyreForm.base_price, catalog_number: tyreForm.catalog_number, product_number: tyreForm.product_number, stock_quantity: parseInt(tyreForm.stock_quantity)||0, season: forcedSeason, vehicle_type: tyreForm.vehicle_type, axis: tyreForm.axis, image_url: finalGallery[0]||null, gallery: finalGallery, is_hot: tyreForm.is_hot, supplier_id: tyreForm.supplier_id ? parseInt(tyreForm.supplier_id) : null, in_stock: true };
      if (editingTyreId) await supabase.from('tyres').update(payload).eq('id', editingTyreId);
      else await supabase.from('tyres').insert([payload]);
      fetchTyres(0, true); setShowAddTyreModal(false);
    } catch (err: any) { setErrorMessage(err.message); } finally { setUploading(false); }
  };

  const openEditTyreModal = (t: TyreProduct) => {
      setEditingTyreId(t.id);
      const m = t.title.match(/(\d{3})[\/\s](\d{2})/);
      setTyreForm({ manufacturer: t.manufacturer||'', name: t.title, width: m?.[1]||'', height: m?.[2]||'', radius: t.radius||'R15', season: t.season||'summer', vehicle_type: t.vehicle_type||'car', price: String(t.price||''), old_price: String(t.old_price||''), base_price: String(t.base_price||''), catalog_number: t.catalog_number||'', product_number: t.product_number||'', description: t.description||'', is_hot: !!t.is_hot, supplier_id: String(t.supplier_id||''), stock_quantity: String(t.stock_quantity||''), axis: t.axis||'' });
      setExistingGallery(t.gallery || (t.image_url ? [t.image_url] : [])); setTyreUploadFiles([]); setShowAddTyreModal(true);
  };

  const getRadiiOptions = (type: string) => type === 'truck' ? TRUCK_RADII : type === 'agro' ? AGRO_RADII : type === 'cargo' ? CARGO_RADII : CAR_RADII;

  return (
    <div className="animate-in fade-in pb-20">
        {errorMessage && <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[300] bg-red-900/90 text-white px-6 py-3 rounded-full border border-red-500 shadow-xl">{errorMessage}</div>}
        {successMessage && <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[300] bg-green-600/90 text-white px-6 py-3 rounded-full border border-green-400 shadow-xl flex items-center gap-2"><CheckCircle size={20} />{successMessage}</div>}

        {/* TOOLBAR */}
        <div className="flex flex-col xl:flex-row gap-3 justify-between mb-4">
            <div className="flex gap-2 w-full xl:w-auto">
                <button onClick={() => setShowCategoryMenu(!showCategoryMenu)} className="bg-zinc-800 text-white font-bold px-4 py-3 rounded-lg flex items-center justify-between gap-2 border border-zinc-700 w-full xl:w-72">
                    <div className="flex items-center gap-2"><Menu size={20} className="text-[#FFC300]"/><span className="uppercase tracking-wide text-sm truncate">{tyreCategoryTab} ({categoryCounts.all})</span></div>
