                    <div className="absolute top-16 left-4 right-4 z-50 bg-zinc-900 border border-zinc-700 rounded-xl shadow-2xl overflow-hidden md:w-72 md:left-0">
                        {['all','car','cargo','truck','agro','suv','hot','no_photo','out_of_stock'].map(cat => (
