                    <button onClick={() => setShowOnlyInStock(!showOnlyInStock)} className={`flex items-center justify-center gap-2 px-3 py-3 rounded-lg border font-bold text-xs ${showOnlyInStock ? 'bg-green-900/30 text-green-400 border-green-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>{showOnlyInStock ? <Eye size={18}/> : <EyeOff size={18}/>}</button>
